    /**
     * Content for a single page/slide.
     *
     * When page extraction is enabled, documents are split into per-page content
     * with associated tables and images mapped to each page.
     *
     * # Performance
     *
     * Uses Arc-wrapped tables and images for memory efficiency:
     * - `Vec<Arc<Table>>` enables zero-copy sharing of table data
     * - `Vec<Arc<ExtractedImage>>` enables zero-copy sharing of image data
     * - Maintains exact JSON compatibility via custom Serialize/Deserialize
     *
     * This reduces memory overhead for documents with shared tables/images
     * by avoiding redundant copies during serialization.
     */
    class PageContent
    {
        public int $page_number;
        public string $content;
        /** @var array<string> */
        public array $tables;
        /** @var array<ExtractedImage> */
        public array $images;
        public ?PageHierarchy $hierarchy;
        public ?bool $is_blank;
        /** @var ?array<LayoutRegion> */
        public ?array $layout_regions;

        /**
         * @param array<string> $tables
         * @param array<ExtractedImage> $images
         * @param ?array<LayoutRegion> $layout_regions
         */
        public function __construct(
            int $page_number,
            string $content,
            array $tables,
            array $images,
            ?PageHierarchy $hierarchy = null,
            ?bool $is_blank = null,
            ?array $layout_regions = null
        ) {}

        public function getPageNumber(): int {}
        public function getContent(): string {}
        /** @return array<string> */
        public function getTables(): array {}
        /** @return array<ExtractedImage> */
        public function getImages(): array {}
        public function getHierarchy(): ?PageHierarchy {}
        public function getIsBlank(): ?bool {}
        /** @return ?array<LayoutRegion> */
        public function getLayoutRegions(): ?array {}
    }

