        public int $rec_batch_num;
        public int $padding;
        public float $drop_score;
        public string $model_tier;

        public function __construct(
            string $language,
            bool $use_angle_cls,
            bool $enable_table_detection,
            float $det_db_thresh,
            float $det_db_box_thresh,
